I understand the issue. The current implementation assumes all package sizes are available to determine the capacity range, but we can refactor it to work with partial data and use the selected package's actual capacity when available.

Here's a refactored version:

```typescript
export const getBatteryCapacityRange = (
  packageSize: Cloud$PackageSize,
  availableBatteryPackages: PackageStateBattery['availablePackageVariants'],
  selectedPackage?: PackageStateBattery['selectedPackage']
) => {
  // Create a map of package sizes to their capacities
  const packageSizeToCapacity = new Map(
    availableBatteryPackages.map((pkg) => [
      pkg.battery_package_size,
      pkg.minimum_battery_capacity,
    ])
  );

  // If this is the selected package and we have its actual capacity, use that
  if (
    selectedPackage?.package_size === packageSize &&
    selectedPackage?.price?.equipment?.batteries?.[0]?.capacity
  ) {
    const actualCapacity = selectedPackage.price.equipment.batteries[0].capacity;
    return {
      minCapacity: actualCapacity,
      maxCapacity: null,
    };
  }

  // If we don't have the package in availableBatteryPackages yet,
  // we can't determine its range
  if (!packageSizeToCapacity.has(packageSize)) {
    return {
      minCapacity: null,
      maxCapacity: null,
    };
  }

  const currentCapacity = packageSizeToCapacity.get(packageSize);

  // Simple logic for determining max capacity based on available packages
  switch (packageSize) {
    case 'small':
      return {
        minCapacity: currentCapacity,
        maxCapacity: packageSizeToCapacity.get('economic') || packageSizeToCapacity.get('large'),
      };
    case 'economic':
      return {
        minCapacity: currentCapacity,
        maxCapacity: packageSizeToCapacity.get('large'),
      };
    case 'large':
      return {
        minCapacity: currentCapacity,
        maxCapacity: null,
      };
    default:
      return {
        minCapacity: null,
        maxCapacity: null,
      };
  }
};
```

